const item = items[0].json;

const dados = item.triagem || {};
const vinculo = dados.vinculo || {};
const rescisao = dados.rescisao || {};
const documentos = item.documentos_recebidos || [];

// ---------- 1. Bloqueios (mínimo pro motor de cálculo rodar) ----------

const bloqueios = [];

if (!vinculo.inicio) {
  bloqueios.push("Data de admissão (vinculo.inicio)");
}

if (vinculo.salario_medio === undefined || vinculo.salario_medio === null || vinculo.salario_medio === "") {
  bloqueios.push("Salário médio (vinculo.salario_medio)");
}

if (!rescisao.tipo) {
  bloqueios.push("Tipo de rescisão (rescisao.tipo)");
} else if (rescisao.tipo !== "ainda_trabalhando" && !vinculo.fim) {
  bloqueios.push("Data de saída (vinculo.fim) — obrigatória quando o vínculo já terminou");
}

const podeGerar = bloqueios.length === 0;

// ---------- 2. Extração de dados da empresa (a partir da CTPS) ----------
// Best-effort via regex — a CTPS Digital tem formato padronizado pelo
// governo, então isso tende a ser estável, mas SEMPRE precisa de
// confirmação humana antes do protocolo (não confie 100% às ciegas).

const ctps = documentos.find(d => d.tipo_documento === "ctps");
const empresa = { razao_social: null, cnpj: null, endereco: null, admissao_ctps: null, salario_ctps: null };

if (ctps && ctps.texto_extraido) {
  const texto = ctps.texto_extraido;

  const matchEstabelecimento = texto.match(/Estabelecimento\s*\n+\s*\*\*(.+?)\*\*/);
  if (matchEstabelecimento) empresa.razao_social = matchEstabelecimento[1].trim();

  const matchCnpj = texto.match(/\*\*CNPJ:\s*([\d.\/-]+)\*\*/);
  if (matchCnpj) empresa.cnpj = matchCnpj[1].trim();

  // linha em negrito imediatamente após o CNPJ costuma ser o endereço
  const matchEndereco = texto.match(/\*\*CNPJ:\s*[\d.\/-]+\*\*\s*\n+\s*\*\*(.+?)\*\*/);
  if (matchEndereco) empresa.endereco = matchEndereco[1].trim();

  const matchAdmissao = texto.match(/(\d{2}\/\d{2}\/\d{4})\s*-\s*(Aberto|Fechado)/);
  if (matchAdmissao) empresa.admissao_ctps = matchAdmissao[1];

  const matchSalario = texto.match(/Salário contratual\s*\n+\s*\*\*R\$\s*([\d.,]+)/);
  if (matchSalario) empresa.salario_ctps = matchSalario[1];
}

// ---------- 3. Divergências entre triagem e documento ----------
// Não bloqueia a geração — mas precisa ficar visível, porque o motor
// de cálculo vai usar os dados da triagem, e alguém (Dr. Lucas) tem
// que confirmar se isso está certo antes do protocolo.

const divergencias = [];

function paraISO(dataBR) {
  if (!dataBR) return null;
  const [d, m, y] = dataBR.split("/");
  return `${y}-${m}-${d}`;
}

if (empresa.admissao_ctps) {
  const admissaoCtpsISO = paraISO(empresa.admissao_ctps);
  if (vinculo.inicio && admissaoCtpsISO && vinculo.inicio !== admissaoCtpsISO) {
    divergencias.push(
      `Data de admissão informada pela cliente (${vinculo.inicio}) diverge da CTPS (${admissaoCtpsISO})`
    );
  }
}

if (empresa.salario_ctps) {
  const salarioCtpsNum = parseFloat(empresa.salario_ctps.replace(".", "").replace(",", "."));
  if (vinculo.salario_medio && Math.abs(vinculo.salario_medio - salarioCtpsNum) > 0.01) {
    divergencias.push(
      `Salário informado pela cliente (R$ ${vinculo.salario_medio}) diverge do salário contratual na CTPS (R$ ${salarioCtpsNum})`
    );
  }
}

// ---------- 4. Pendências já conhecidas pela entrevista ----------

const pendenciasConhecidas = Array.isArray(dados.pendencias_peticao)
  ? dados.pendencias_peticao
  : [];

return [{
  json: {
    id: item.id,
    nome: item.cliente_nome_completo || item.nome,
    telefone: item.telefone,
    triagem: dados,
    documentos_recebidos: documentos,
    empresa,
    pode_gerar: podeGerar,
    bloqueios,
    divergencias,
    pendencias_conhecidas: pendenciasConhecidas,
  },
}];

const classificacao = items[0].json.output || {};
const item = $('Valida se tem os dados necessários para a petição').first().json;

const HONORARIOS_PCT = 0.15;
const ALIQUOTA_FGTS = 0.08;
const MULTA_FGTS_PCT = 0.40;
const PLUS_ACUMULO_FUNCAO_PCT = 0.20;

const dados = item.triagem || {};
const vinculo = dados.vinculo || {};
const rescisao = dados.rescisao || {};
const direitos = dados.direitos || {};
const empresa = item.empresa || {};
const tesesAtivas = classificacao.teses_ativas || [];

const alertas = [];

function formatBRL(valor) {
  if (typeof valor !== "number" || !Number.isFinite(valor)) return "R$ 0,00 (⚠️ valor inválido)";
  return valor.toLocaleString("pt-BR", { style: "currency", currency: "BRL" });
}

function parseDataISO(str) {
  if (!str) return null;
  const [y, m, d] = str.split("-").map(Number);
  const data = new Date(y, m - 1, d);
  return isNaN(data.getTime()) ? null : data;
}

function parseDataBR(str) {
  if (!str) return null;
  const [d, m, y] = str.split("/").map(Number);
  const data = new Date(y, m - 1, d);
  return isNaN(data.getTime()) ? null : data;
}

function diferencaEmMeses(inicio, fim) {
  if (!inicio || !fim) return 0;
  return (fim.getFullYear() - inicio.getFullYear()) * 12
    + (fim.getMonth() - inicio.getMonth())
    + (fim.getDate() >= inicio.getDate() ? 0 : -1);
}

// 🆕 versão fracionada (dias reais / 30) — usada onde a diferença de
// dias importa de verdade pro valor final (ex: FGTS de período parcial)
function mesesFracionados(inicio, fim) {
  if (!inicio || !fim) return 0;
  const diffDias = (fim - inicio) / (1000 * 60 * 60 * 24);
  return diffDias / 30;
}

function diferencaEmAnosCompletos(inicio, fim) {
  return Math.floor(diferencaEmMeses(inicio, fim) / 12);
}

// 🆕 CORRIGIDO — compara dias decorridos desde o "aniversário" do
// período (dia de inicioPeriodo), não o dia absoluto do calendário
function mesesProporcionais(inicioPeriodo, dataFim) {
  let meses = (dataFim.getFullYear() - inicioPeriodo.getFullYear()) * 12
    + (dataFim.getMonth() - inicioPeriodo.getMonth());
  let diasExtras = dataFim.getDate() - inicioPeriodo.getDate();
  if (diasExtras < 0) {
    meses -= 1;
    diasExtras += 30;
  }
  if (diasExtras >= 15) meses += 1;
  return Math.max(0, Math.min(meses, 12));
}

function temTese(id) {
  return tesesAtivas.some(t => t.id === id);
}

function pegaTese(id) {
  return tesesAtivas.find(t => t.id === id) || null;
}

// ---------- Motor de reflexo (CORRIGIDO) ----------
// bloco.valor agora é sempre o TOTAL acumulado no período. O reflexo
// deriva a taxa mensal de volta (valor ÷ meses) antes de aplicar a
// fração do ano — nunca multiplica o total de novo pelo tempo.
function aplicarReflexos(bloco) {
  const linhas = [{ verba: bloco.nome, valor: bloco.valor }];

  if (bloco.gera_reflexo && bloco.natureza === "recorrente" && bloco.meses_para_reflexo > 0) {
    const valorMensal = bloco.valor / bloco.meses_para_reflexo;
    const fracao = bloco.meses_para_reflexo / 12;
    linhas.push({ verba: `Reflexo de "${bloco.nome}" em 13º salário`, valor: valorMensal * fracao });
    linhas.push({ verba: `Reflexo de "${bloco.nome}" em férias + 1/3`, valor: valorMensal * fracao * (4 / 3) });
  }

  if (bloco.gera_fgts) {
    const baseFgts = linhas.reduce((s, l) => s + l.valor, 0);
    linhas.push({ verba: `FGTS sobre "${bloco.nome}" e reflexos`, valor: baseFgts * ALIQUOTA_FGTS, _fgts: true });
  }

  return linhas;
}

// ---------- Datas de referência ----------

const dataAdmissao = parseDataISO(vinculo.inicio);
let dataSaida;

if (vinculo.fim) {
  dataSaida = parseDataISO(vinculo.fim);
  if (rescisao.tipo === "ainda_trabalhando") {
    alertas.push(
      `rescisao.tipo diz "ainda_trabalhando", mas vinculo.fim (${vinculo.fim}) está preenchido. ` +
      `Usando vinculo.fim como data de saída — CONFIRMAR qual está correto.`
    );
  }
} else if (rescisao.tipo === "ainda_trabalhando") {
  dataSaida = new Date();
} else {
  alertas.push("Não há vinculo.fim nem indicação de vínculo em curso — data de saída indeterminada.");
  dataSaida = null;
}

const salario = vinculo.salario_medio;
const mesesTrabalhados = (dataSaida && dataAdmissao) ? diferencaEmMeses(dataAdmissao, dataSaida) : null;
const anosCompletos = (dataSaida && dataAdmissao) ? diferencaEmAnosCompletos(dataAdmissao, dataSaida) : null;
const diasNoUltimoMes = dataSaida ? dataSaida.getDate() : null;

if (!salario) alertas.push("Salário médio ausente — nenhuma verba foi calculada.");
if (vinculo.inicio && !dataAdmissao) alertas.push(`Data de admissão inválida: "${vinculo.inicio}" — verificar formato.`);

const ctx = { dados, vinculo, rescisao, direitos, empresa, salario, dataAdmissao, dataSaida, mesesTrabalhados, anosCompletos, diasNoUltimoMes, alertas, tesesAtivas };

// ---------- Catálogo de blocos ----------

const CATALOGO_BLOCOS = [

  {
    id: "saldo_salario",
    condicao: c => !!(c.salario && c.dataSaida),
    calcular: c => ({
      nome: "Saldo de salário",
      valor: (c.salario / 30) * c.diasNoUltimoMes,
      natureza: "unica", gera_fgts: false, gera_reflexo: false,
    }),
  },

  {
    id: "aviso_previo",
    condicao: c => !!(c.salario && c.dataSaida && c.anosCompletos !== null) && !["pediu", "justa_causa"].includes(c.rescisao.tipo || "sem_justa_causa"),
    calcular: c => {
      if (!c.rescisao.tipo) c.alertas.push('Tipo de rescisão não confirmado — aviso prévio assumindo "sem justa causa". CONFIRMAR.');
      const dias = Math.min(30 + (3 * c.anosCompletos), 90);
      return {
        nome: `Aviso prévio indenizado (${dias} dias)`,
        valor: (c.salario / 30) * dias,
        natureza: "unica", gera_fgts: true, gera_reflexo: false,
      };
    },
  },

  {
    id: "decimo_terceiro_proporcional",
    condicao: c => !!(c.salario && c.dataSaida && c.dataAdmissao),
    calcular: c => {
      const inicioAno = new Date(c.dataSaida.getFullYear(), 0, 1);
      const inicioPeriodo = c.dataAdmissao > inicioAno ? c.dataAdmissao : inicioAno;
      const meses = mesesProporcionais(inicioPeriodo, c.dataSaida);
      return {
        nome: `13º salário proporcional (${meses}/12)`,
        valor: (c.salario / 12) * meses,
        natureza: "unica", gera_fgts: true, gera_reflexo: false,
      };
    },
  },

  {
    id: "ferias_proporcionais",
    condicao: c => !!(c.salario && c.dataSaida && c.dataAdmissao && c.anosCompletos !== null),
    calcular: c => {
      const inicioPeriodoAquisitivo = new Date(c.dataAdmissao);
      inicioPeriodoAquisitivo.setFullYear(c.dataAdmissao.getFullYear() + c.anosCompletos);
      const meses = mesesProporcionais(inicioPeriodoAquisitivo, c.dataSaida);
      const base = (c.salario / 12) * meses;
      return {
        nome: `Férias proporcionais + 1/3 (${meses}/12)`,
        valor: base + (base / 3),
        natureza: "unica", gera_fgts: false, gera_reflexo: false,
      };
    },
  },

  {
    id: "ferias_vencidas",
    condicao: c => (c.direitos.ferias_terco === true || c.dados.ferias_terco === true) && !!c.salario,
    calcular: c => {
      c.alertas.push('Férias vencidas calculadas para 1 período — CONFIRMAR quantos períodos completos não foram gozados.');
      return {
        nome: "Férias vencidas (1 período) + 1/3",
        valor: c.salario + (c.salario / 3),
        natureza: "unica", gera_fgts: false, gera_reflexo: false,
      };
    },
  },

  {
    id: "multa_477",
    condicao: c => !!(c.dataSaida && c.salario) && !["pediu", "justa_causa", "acordo"].includes(c.rescisao.tipo || ""),
    calcular: c => ({
      nome: "Multa do art. 477 da CLT",
      valor: c.salario,
      natureza: "unica", gera_fgts: false, gera_reflexo: false,
    }),
  },

  {
    id: "seguro_desemprego",
    condicao: c => !!(c.dataSaida && c.salario && c.mesesTrabalhados) && !["pediu", "justa_causa", "acordo"].includes(c.rescisao.tipo || "") && c.mesesTrabalhados >= 6,
    calcular: c => {
      c.alertas.push("Seguro-desemprego calculado sem aplicar o teto legal do benefício — ajustar manualmente se o salário exceder a faixa.");
      return {
        nome: "Indenização substitutiva do seguro-desemprego (4 parcelas)",
        valor: c.salario * 4,
        natureza: "unica", gera_fgts: false, gera_reflexo: false,
      };
    },
  },

  {
    id: "diferenca_salarial_ctps",
    condicao: c => {
      const ctpsNum = c.empresa.salario_ctps ? parseFloat(String(c.empresa.salario_ctps).replace(".", "").replace(",", ".")) : null;
      return !!(ctpsNum && !isNaN(ctpsNum) && c.salario && c.salario > ctpsNum && c.mesesTrabalhados);
    },
    calcular: c => {
      const ctpsNum = parseFloat(String(c.empresa.salario_ctps).replace(".", "").replace(",", "."));
      const diferencaMensal = c.salario - ctpsNum;
      c.alertas.push(`Diferença salarial detectada entre o valor reclamado e o registrado na CTPS (R$ ${diferencaMensal.toFixed(2)}/mês) — CONFIRMAR se é diferença legítima ou erro de informação.`);
      return {
        nome: `Diferenças salariais não quitadas (R$ ${diferencaMensal.toFixed(2)}/mês × ${c.mesesTrabalhados} meses)`,
        valor: diferencaMensal * c.mesesTrabalhados,
        natureza: "recorrente", meses_para_reflexo: c.mesesTrabalhados,
        gera_fgts: true, gera_reflexo: true,
      };
    },
  },

  // 🆕 CORRIGIDO — meses fracionados (não trunca dias), e SEM passar
  // pelo motor de reflexo genérico (FGTS não gera "reflexo em 13º/férias"
  // — isso não existe; o que existe é FGTS sobre o 13º daquele período,
  // calculado como uma linha própria).
  {
    id: "vinculo_sem_registro",
    condicao: c => temTese("vinculo_sem_registro") && !!c.empresa.admissao_ctps && !!c.dataAdmissao,
    calcularLinhas: c => {
      const dataRegistro = parseDataBR(c.empresa.admissao_ctps);
      if (!dataRegistro) {
        c.alertas.push(`Tese "vínculo sem registro" identificada, mas a data da CTPS ("${c.empresa.admissao_ctps}") não pôde ser interpretada — CONFIRMAR manualmente.`);
        return [];
      }

      const mesesSemRegistro = mesesFracionados(c.dataAdmissao, dataRegistro);
      if (mesesSemRegistro <= 0) {
        c.alertas.push('Tese "vínculo sem registro" identificada, mas a diferença de datas calculada não é positiva — CONFIRMAR manualmente as datas.');
        return [];
      }

      c.alertas.push(`Vínculo sem registro: considerando o período de ${c.vinculo.inicio} até ${dataRegistro.toISOString().slice(0,10)} (≈${mesesSemRegistro.toFixed(1)} meses) — CONFIRMAR com a cliente antes de protocolar.`);

      const fgtsSalario = c.salario * ALIQUOTA_FGTS * mesesSemRegistro;
      // proporção do período sem registro dentro de um ano (13º daquele período)
      const decimoDoPeriodo = (c.salario / 12) * Math.min(mesesSemRegistro, 12);
      const fgtsSobre13 = decimoDoPeriodo * ALIQUOTA_FGTS;

      return [
        { verba: `FGTS do período sem registro (≈${mesesSemRegistro.toFixed(1)} meses)`, valor: fgtsSalario },
        { verba: `FGTS sobre o 13º proporcional incidente no período sem registro`, valor: fgtsSobre13 },
      ];
    },
  },

  {
    id: "acumulo_funcao",
    condicao: c => temTese("acumulo_funcao") && !!(c.salario && c.mesesTrabalhados),
    calcular: c => {
      const tese = pegaTese("acumulo_funcao");
      c.alertas.push(`Acúmulo de função identificado (${(tese.parametros?.atividades_identificadas || []).join(", ")}) — percentual de 20% aplicado por convenção do escritório. CONFIRMAR percentual com o Dr. Lucas.`);
      return {
        nome: "Plus salarial por acúmulo de função (20%)",
        valor: c.salario * PLUS_ACUMULO_FUNCAO_PCT * c.mesesTrabalhados,
        natureza: "recorrente", meses_para_reflexo: c.mesesTrabalhados,
        gera_fgts: true, gera_reflexo: true,
      };
    },
  },

  {
    id: "dano_moral",
    condicao: c => temTese("dano_moral"),
    calcular: c => {
      const tese = pegaTese("dano_moral");
      c.alertas.push(`Dano moral identificado pelo classificador (fundamento: "${tese.parametros?.fundamento || "não especificado"}") — valor NÃO calculado. Dr. Lucas precisa arbitrar manualmente antes de gerar a petição.`);
      return null;
    },
  },

];

// ---------- Aplica o catálogo ----------

let verbas = [];

if (salario && dataSaida && dataAdmissao) {
  for (const bloco of CATALOGO_BLOCOS) {
    if (bloco.condicao(ctx)) {
      // 🆕 suporte a blocos que devolvem linhas prontas (sem motor de reflexo)
      if (bloco.calcularLinhas) {
        const linhas = bloco.calcularLinhas(ctx).filter(l => Number.isFinite(l.valor));
        verbas = verbas.concat(linhas);
        continue;
      }
      const resultado = bloco.calcular(ctx);
      if (resultado && Number.isFinite(resultado.valor)) {
        verbas = verbas.concat(aplicarReflexos(resultado));
      } else if (resultado) {
        alertas.push(`Bloco "${resultado.nome}" gerou valor inválido e foi descartado — verificar dados de entrada.`);
      }
    }
  }

  const totalFgts = verbas.filter(v => v._fgts).reduce((s, v) => s + v.valor, 0);
  if (totalFgts > 0) {
    verbas.push({ verba: "Multa de 40% do FGTS", valor: totalFgts * MULTA_FGTS_PCT });
  }
}

const idsComBloco = new Set(CATALOGO_BLOCOS.map(b => b.id));
const tesesNaoCobertas = tesesAtivas.filter(t => !idsComBloco.has(t.id));

if (tesesNaoCobertas.length) {
  alertas.push(`Teses identificadas pelo classificador mas SEM bloco de cálculo ainda: ${tesesNaoCobertas.map(t => t.id).join(", ")}. Calcular manualmente antes de finalizar.`);
}

const valorTotalVerbas = verbas.reduce((s, v) => s + v.valor, 0);
const valorHonorarios = valorTotalVerbas * HONORARIOS_PCT;
const valorGeralEstimado = valorTotalVerbas + valorHonorarios;

const liquidacaoTexto = verbas.map(v => `- ${v.verba}: ${formatBRL(v.valor)}`).join("\n");

return [{
  json: {
    ...item,
    teses_ativas: tesesAtivas,
    verbas,
    valor_total_verbas: valorTotalVerbas,
    valor_honorarios: valorHonorarios,
    valor_geral_estimado: valorGeralEstimado,
    liquidacao_provisoria_texto: liquidacaoTexto,
    alertas_calculo: alertas,
  },
}];

